export type ResolvedAcpxConfig = {
  defaultAgent: string;
  defaultPermissions: PermissionMode;
  nonInteractivePermissions: NonInteractivePermissionPolicy;
  authPolicy: AuthPolicy;
  ttlMs: number;
  timeoutMs?: number;
  queueMaxDepth: number;
  format: OutputFormat;
  agents: Record<string, string>;
