                              class="btn btn--sm md-preview-expand-btn"
                              title="Toggle fullscreen"
                              @click=${(e: Event) => {
                                const btn = e.currentTarget as HTMLElement;
                                const panel = btn.closest(".md-preview-dialog__panel");
                                if (!panel) {
