                              ><span class="when-fullscreen">${icons.minimize} Collapse</span>
                            </button>
                            <button
                              class="btn btn--sm"
                              title="Edit file"
                              @click=${(e: Event) => {
                                (e.currentTarget as HTMLElement).closest("dialog")?.close();
                                const textarea =
                                  document.querySelector<HTMLElement>(".agent-file-textarea");
                                textarea?.focus();
                              }}
                            >
                              ${icons.edit} Editor
