    const ctx = init;
    pendingQuestions.set(ctx.questionId, ctx);
    const baseKey = (0, chat_queue_1.buildQueueKey)(ctx.accountId, ctx.chatId);
    let set = byChatContext.get(baseKey);
    if (!set) {
        set = new Set();
        byChatContext.set(baseKey, set);
    }
    set.add(ctx.questionId);
