        ctx = findQuestionByChat(accountId, openChatId);
        if (ctx) {
            log.info(`resolved question via chat-scoped fallback: ${ctx.questionId}`);
        }
    }
    if (!ctx) {
        if (operationId) {
            log.warn(`ask-user action: question ${operationId} not found (expired or already handled)`);
        }
