    scope: string;
    isBatchAuth?: boolean;
    totalAppScopes?: number;
    alreadyGranted?: number;
    batchInfo?: string;
    skipSyntheticMessage?: boolean;
    showBatchAuthHint?: boolean;
    forceAuth?: boolean;
    onAuthComplete?: () => void | Promise<void>;
    cfg: ClawdbotConfig;
    ticket: LarkTicket | undefined;
}
